class Solution {
    public int nextBeautifulNumber(int n) {
        while (true) {
            n++;
            if (isNumericallyBalanced(n)) {
                return n;
            }
        }
    }
    private boolean isNumericallyBalanced(int num) {
        int[] counts = new int[10];
        while (num > 0) {
            int digit = num % 10;
            counts[digit]++;
            num /= 10;
        }
        for (int i = 0; i < 10; i++) {
            if (counts[i] != i) {
                return false;
            }
        }
        return true;
    }
}
```
